{"content":"1: package keyring
2: 
3: import (
4: 	"context"
5: 	"reflect"
6: 	"sync"
7: 
8: 	"github.com/sourcegraph/sourcegraph/internal/conf"
9: 	"github.com/sourcegraph/sourcegraph/internal/encryption"
10: 	"github.com/sourcegraph/sourcegraph/internal/encryption/awskms"
11: 	"github.com/sourcegraph/sourcegraph/internal/encryption/cache"
12: 	"github.com/sourcegraph/sourcegraph/internal/encryption/cloudkms"
13: 	"github.com/sourcegraph/sourcegraph/internal/encryption/mounted"
14: 	"github.com/sourcegraph/sourcegraph/lib/errors"
15: 	"github.com/sourcegraph/sourcegraph/schema"
16: )
17: 
18: var (
19: 	mu          sync.RWMutex
20: 	defaultRing Ring
21: )
22: 
23: // Default returns the default keyring, if you can avoid using this from arbitrary points in your code, please do!
24: // we would rather inject the individual keys as dependencies when initialised from main(), but if that's impractical
25: // it's fine to use this.
26: func Default() Ring {
27: 	mu.RLock()
28: 	defer mu.RUnlock()
29: 	return defaultRing
30: }
31: 
32: // TB is the subset of testing.TB we need for MockDefault
33: type TB interface {
34: 	Cleanup(func())
35: 	Setenv(key, value string)
36: }
37: 
38: // MockDefault overrides the default keyring.
39: // Note: This function is defined for testing purpose.
40: // Use Init to correctly setup a keyring.
41: func MockDefault(t TB, r Ring) {
42: 	// The side-effect of Setenv is you can't call t.Parallel with it. This
43: 	// prevents races with other tests that call MockDefault or tests that
44: 	// directly use Default.
45: 	t.Setenv("MOCKED", "YES")
46: 
47: 	old := Default()
48: 	t.Cleanup(func() {
49: 		mu.Lock()
50: 		defer mu.Unlock()
51: 		defaultRing = old
52: 	})
53: 
54: 	mu.Lock()
55: 	defer mu.Unlock()
56: 	defaultRing = r
57: }
58: 
59: func Init(ctx context.Context) error {
60: 	var initialErr error
61: 	handleErr := func(err error) {
62: 		initialErr = err
63: 	}
64: 
65: 	conf.WatchValue(
66: 		func(cfg *conf.Unified) *schema.EncryptionKeys { return cfg.EncryptionKeys },
67: 		func(prev, next *schema.EncryptionKeys) bool { return reflect.DeepEqual(prev, next) },
68: 		func(newConfig *schema.EncryptionKeys) {
69: 			newRing, err := NewRing(ctx, newConfig)
70: 			if err != nil {
71: 				handleErr(err)
72: 				return
73: 			}
74: 			mu.Lock()
75: 			defaultRing = *newRing
76: 			mu.Unlock()
77: 		},
78: 	)
79: 
80: 	// From now on we can't return errors that happen, so we panic
81: 	handleErr = func(err error) {
82: 		panic("creating encryption keyring: " + err.Error())
83: 	}
84: 
85: 	return initialErr
86: }
87: 
88: // NewRing creates a keyring.Ring containing all the keys configured in site config
89: func NewRing(ctx context.Context, keyConfig *schema.EncryptionKeys) (*Ring, error) {
90: 	if keyConfig == nil {
91: 		return &Ring{}, nil
92: 	}
93: 
94: 	var (
95: 		r   Ring
96: 		err error
97: 	)
98: 
99: 	if keyConfig.BatchChangesCredentialKey != nil {
100: 		r.BatchChangesCredentialKey, err = NewKey(ctx, keyConfig.BatchChangesCredentialKey, keyConfig)
101: 		if err != nil {
102: 			return nil, err
103: 		}
104: 	}
105: 
106: 	if keyConfig.ExternalServiceKey != nil {
107: 		r.ExternalServiceKey, err = NewKey(ctx, keyConfig.ExternalServiceKey, keyConfig)
108: 		if err != nil {
109: 			return nil, err
110: 		}
111: 	}
112: 
113: 	if keyConfig.GitHubAppKey != nil {
114: 		r.GitHubAppKey, err = NewKey(ctx, keyConfig.GitHubAppKey, keyConfig)
115: 		if err != nil {
116: 			return nil, err
117: 		}
118: 	}
119: 
120: 	if keyConfig.UserExternalAccountKey != nil {
121: 		r.UserExternalAccountKey, err = NewKey(ctx, keyConfig.UserExternalAccountKey, keyConfig)
122: 		if err != nil {
123: 			return nil, err
124: 		}
125: 	}
126: 
127: 	if keyConfig.WebhookKey != nil {
128: 		r.WebhookKey, err = NewKey(ctx, keyConfig.WebhookKey, keyConfig)
129: 		if err != nil {
130: 			return nil, err
131: 		}
132: 	}
133: 
134: 	if keyConfig.WebhookLogKey != nil {
135: 		r.WebhookLogKey, err = NewKey(ctx, keyConfig.WebhookLogKey, keyConfig)
136: 		if err != nil {
137: 			return nil, err
138: 		}
139: 	}
140: 
141: 	if keyConfig.ExecutorSecretKey != nil {
142: 		r.ExecutorSecretKey, err = NewKey(ctx, keyConfig.ExecutorSecretKey, keyConfig)
143: 		if err != nil {
144: 			return nil, err
145: 		}
146: 	}
147: 
148: 	if keyConfig.SlackConfigurationKey != nil {
149: 		r.SlackConfigurationKey, err = NewKey(ctx, keyConfig.SlackConfigurationKey, keyConfig)
150: 		if err != nil {
151: 			return nil, err
152: 		}
153: 	}
154: 
155: 	return &r, nil
156: }
157: 
158: type Ring struct {
159: 	BatchChangesCredentialKey encryption.Key
160: 	ExternalServiceKey        encryption.Key
161: 	GitHubAppKey              encryption.Key
162: 	OutboundWebhookKey        encryption.Key
163: 	UserExternalAccountKey    encryption.Key
164: 	WebhookKey                encryption.Key
165: 	WebhookLogKey             encryption.Key
166: 	ExecutorSecretKey         encryption.Key
167: 	SlackConfigurationKey     encryption.Key
168: }
169: 
170: func NewKey(ctx context.Context, k *schema.EncryptionKey, config *schema.EncryptionKeys) (encryption.Key, error) {
171: 	if k == nil {
172: 		return nil, errors.Errorf("cannot configure nil key")
173: 	}
174: 	var (
175: 		key encryption.Key
176: 		err error
177: 	)
178: 	switch {
179: 	case k.Cloudkms != nil:
180: 		key, err = cloudkms.NewKey(ctx, *k.Cloudkms)
181: 	case k.Awskms != nil:
182: 		key, err = awskms.NewKey(ctx, *k.Awskms)
183: 	case k.Mounted != nil:
184: 		key, err = mounted.NewKey(ctx, *k.Mounted)
185: 	case k.Noop != nil:
186: 		key = &encryption.NoopKey{}
187: 	default:
188: 		return nil, errors.Errorf("couldn't configure key: %v", *k)
189: 	}
190: 	if err != nil {
191: 		return nil, err
192: 	}
193: 
194: 	if config.EnableCache {
195: 		key, err = cache.New(key, config.CacheSize)
196: 	}
197: 	return key, err
198: }
