{"content":"1: package encryption
2: 
3: import (
4: 	"context"
5: 	"encoding/json"
6: )
7: 
8: // Key combines the Encrypter & Decrypter interfaces.
9: type Key interface {
10: 	Encrypter
11: 	Decrypter
12: 
13: 	// Version returns info containing to concretely identify
14: 	// the underlying key, eg: key type, name, & version.
15: 	Version(ctx context.Context) (KeyVersion, error)
16: }
17: 
18: type KeyVersion struct {
19: 	// TODO: generate this as an enum from JSONSchema
20: 	Type    string
21: 	Name    string
22: 	Version string
23: }
24: 
25: func (v KeyVersion) JSON() string {
26: 	buf, _ := json.Marshal(v)
27: 	return string(buf)
28: }
29: 
30: // Encrypter is anything that can encrypt a value
31: type Encrypter interface {
32: 	Encrypt(ctx context.Context, value []byte) ([]byte, error)
33: }
34: 
35: // Decrypter is anything that can decrypt a value
36: type Decrypter interface {
37: 	Decrypt(ctx context.Context, cipherText []byte) (*Secret, error)
38: }
39: 
40: func NewSecret(v string) Secret {
41: 	return Secret{
42: 		value: v,
43: 	}
44: }
45: 
46: // Secret is a utility type to make it harder to accidentally leak secret
47: // values in logs. The actual value is unexported inside a struct, making
48: // harder to leak via reflection, the string value is only ever returned
49: // on explicit Secret() calls, meaning we can statically analyse secret
50: // usage and statically detect leaks.
51: type Secret struct {
52: 	value string
53: }
54: 
55: // String implements stringer, obfuscating the value
56: func (s Secret) String() string {
57: 	return "********"
58: }
59: 
60: // Secret returns the unobfuscated value
61: func (s Secret) Secret() string {
62: 	return s.value
63: }
64: 
65: // MarshalJSON overrides the default JSON marshaling implementation, obfuscating
66: // the value in any marshaled JSON
67: func (s Secret) MarshalJSON() ([]byte, error) {
68: 	return []byte(s.String()), nil
69: }
70: ","url":"https://sourcegraph.sourcegraph.com/github.com/sourcegraph/sourcegraph@2182d53b963752f43e9f39205715f71160798bb2/-/blob/internal/encryption/key.go"}

