{"content":"1: package encryption
2: 
3: import (
4: 	"context"
5: 	"sync"
6: 
7: 	"github.com/sourcegraph/sourcegraph/lib/errors"
8: )
9: 
10: // Encryptable wraps a value and an encryption key and handles lazily encrypting and
11: // decrypting that value. This struct should be used in all places where a value is
12: // encrypted at-rest to maintain a consistent handling of data with security concerns.
13: //
14: // This struct should always be passed by reference.
15: type Encryptable struct {
16: 	mutex     sync.Mutex
17: 	decrypted *decryptedValue
18: 	encrypted *encryptedValue
19: 	key       Key
20: }
21: 
22: type decryptedValue struct {
23: 	value string
24: 	err   error
25: }
26: 
27: // encryptedValue wraps an encrypted value and serialized metadata about that key that
28: // encrypted it.
29: type encryptedValue struct {
30: 	Cipher string
31: 	KeyID  string
32: }
33: 
34: // NewUnencrypted creates a new encryptable from a plaintext value.
35: func NewUnencrypted(value string) *Encryptable {
36: 	return &Encryptable{
37: 		decrypted: &decryptedValue{value, nil},
38: 	}
39: }
40: 
41: // NewEncrypted creates a new encryptable from an encrypted value and a relevant encryption key.
42: func NewEncrypted(cipher, keyID string, key Key) *Encryptable {
43: 	return &Encryptable{
44: 		encrypted: &encryptedValue{cipher, keyID},
45: 		key:       key,
46: 	}
47: }
48: 
49: func (e *Encryptable) Equal(ctx context.Context, f *Encryptable) (bool, error) {
50: 	s1, err := e.Decrypt(ctx)
51: 	if err != nil {
52: 		return false, err
53: 	}
54: 	s2, err := f.Decrypt(ctx)
55: 	if err != nil {
56: 		return false, err
57: 	}
58: 	return s1 == s2, nil
59: }
60: 
61: // Decrypt returns the underlying plaintext value. This method may make an external API call to
62: // decrypt the underlying encrypted value, but will memoize the result so that subsequent calls
63: // will be cheap.
64: func (e *Encryptable) Decrypt(ctx context.Context) (string, error) {
65: 	e.mutex.Lock()
66: 	defer e.mutex.Unlock()
67: 
68: 	return e.decryptLocked(ctx)
69: }
70: 
71: func (e *Encryptable) decryptLocked(ctx context.Context) (string, error) {
72: 	if e.decrypted != nil {
73: 		return e.decrypted.value, e.decrypted.err
74: 	}
75: 	if e.encrypted == nil {
76: 		return "", errors.New("no encrypted value")
77: 	}
78: 
79: 	value, err := MaybeDecrypt(ctx, e.key, e.encrypted.Cipher, e.encrypted.KeyID)
80: 	e.decrypted = &decryptedValue{value, err}
81: 	return value, err
82: }
83: 
84: // Encrypt returns the underlying encrypted value. This method may make an external API call to
85: // encrypt the underlying plaintext value, but will memoize the result so that subsequent calls
86: // will be cheap.
87: func (e *Encryptable) Encrypt(ctx context.Context, key Key) (string, string, error) {
88: 	if err := e.SetKey(ctx, key); err != nil {
89: 		return "", "", err
90: 	}
91: 
92: 	e.mutex.Lock()
93: 	defer e.mutex.Unlock()
94: 
95: 	if e.encrypted != nil {
96: 		return e.encrypted.Cipher, e.encrypted.KeyID, nil
97: 	}
98: 	if e.decrypted == nil {
99: 		return "", "", errors.New("nothing to encrypt")
100: 	}
101: 
102: 	cipher, keyID, err := MaybeEncrypt(ctx, e.key, e.decrypted.value)
103: 	if err != nil {
104: 		return "", "", err
105: 	}
106: 
107: 	e.encrypted = &encryptedValue{cipher, keyID}
108: 	return cipher, keyID, err
109: }
110: 
111: // Set updates the underlying plaintext value.
112: func (e *Encryptable) Set(value string) {
113: 	e.mutex.Lock()
114: 	defer e.mutex.Unlock()
115: 
116: 	e.decrypted = &decryptedValue{value, nil}
117: 	e.encrypted = nil
118: }
119: 
120: // SetKey updates the encryption key used with the encrypted value. This method may trigger an
121: // external API call to decrypt the current value.
122: func (e *Encryptable) SetKey(ctx context.Context, key Key) error {
123: 	e.mutex.Lock()
124: 	defer e.mutex.Unlock()
125: 
126: 	if e.key == key {
127: 		return nil
128: 	}
129: 
130: 	if _, err := e.decryptLocked(ctx); err != nil {
131: 		return err
132: 	}
133: 
134: 	e.key = key
135: 	e.encrypted = nil
136: 	return nil
137: }
138: ","url":"https://sourcegraph.sourcegraph.com/github.com/sourcegraph/sourcegraph@2182d53b963752f43e9f39205715f71160798bb2/-/blob/internal/encryption/encryptable.go"}

{"content":"1: package encryption
2: 
3: import (
4: 	"context"
5: 	"os"
6: 
7: 	"github.com/sourcegraph/sourcegraph/internal/trace"
8: 	"github.com/sourcegraph/sourcegraph/lib/errors"
9: )
10: 
11: const UnmigratedEncryptionKeyID = "unmigrated"
12: 
13: // MaybeEncrypt encrypts data with the given key. If the given key is nil, this function no-ops.
14: func MaybeEncrypt(ctx context.Context, key Key, data string) (_, keyIdent string, err error) {
15: 	if key == nil {
16: 		return data, "", nil
17: 	}
18: 	if os.Getenv("ALLOW_DECRYPTION") == "true" {
19: 		// Do not encrypt new values while the worker is decrypting the database
20: 		return data, "", nil
21: 	}
22: 
23: 	tr, trCtx := trace.New(ctx, "key.Encrypt")
24: 	encrypted, err := key.Encrypt(trCtx, []byte(data))
25: 	tr.EndWithErr(&err)
26: 	if err != nil {
27: 		return "", "", err
28: 	}
29: 
30: 	tr, trCtx = trace.New(ctx, "key.Version")
31: 	version, err := key.Version(trCtx)
32: 	tr.EndWithErr(&err)
33: 	if err != nil {
34: 		return "", "", errors.Wrap(err, "failed to get encryption key version")
35: 	}
36: 
37: 	return string(encrypted), version.JSON(), nil
38: }
39: 
40: // MaybeDecrypt decrypts data given key. If the value is not encrypted, this function no-ops. If the given
41: // key cannot decrypt the data, an error is returned.
42: func MaybeDecrypt(ctx context.Context, key Key, data, keyIdent string) (string, error) {
43: 	if keyIdent == "" || keyIdent == UnmigratedEncryptionKeyID {
44: 		return data, nil
45: 	}
46: 	if data == "" {
47: 		return data, nil
48: 	}
49: 	if key == nil {
50: 		return data, errors.Errorf("key mismatch: value is encrypted but no encryption key available in site-config")
51: 	}
52: 
53: 	tr, innerCtx := trace.New(ctx, "key.Decrypt")
54: 	decrypted, err := key.Decrypt(innerCtx, []byte(data))
55: 	tr.EndWithErr(&err)
56: 	if err != nil {
57: 		tr, innerCtx = trace.New(ctx, "key.Version")
58: 		version, versionErr := key.Version(innerCtx)
59: 		tr.EndWithErr(&versionErr)
60: 		if versionErr == nil && keyIdent != version.JSON() {
61: 			return "", errors.New("key mismatch: value is encrypted with an encryption key distinct from the one available in site-config")
62: 		}
63: 
64: 		return data, err
65: 	}
66: 
67: 	return decrypted.Secret(), nil
68: }
69: ","url":"https://sourcegraph.sourcegraph.com/github.com/sourcegraph/sourcegraph@2182d53b963752f43e9f39205715f71160798bb2/-/blob/internal/encryption/helpers.go"}

{"content":"1: package mounted
2: 
3: import (
4: 	"context"
5: 	"crypto/aes"
6: 	"crypto/cipher"
7: 	"os"
8: 	"strings"
9: 
10: 	"github.com/sourcegraph/sourcegraph/internal/encryption"
11: 	"github.com/sourcegraph/sourcegraph/internal/encryption/aeshelper"
12: 	"github.com/sourcegraph/sourcegraph/internal/encryption/envelope"
13: 	"github.com/sourcegraph/sourcegraph/internal/encryption/wrapper"
14: 	"github.com/sourcegraph/sourcegraph/lib/errors"
15: 	"github.com/sourcegraph/sourcegraph/schema"
16: )
17: 
18: const (
19: 	mechanismEncrypt  = "encrypt"
20: 	mechanismEnvelope = "envelope"
21: )
22: 
23: func NewKey(ctx context.Context, k schema.MountedEncryptionKey) (*Key, error) {
24: 	var secret []byte
25: 	if k.EnvVarName != "" && k.Filepath == "" {
26: 		secret = []byte(os.Getenv(k.EnvVarName))
27: 
28: 	} else if k.Filepath != "" && k.EnvVarName == "" {
29: 		keyBytes, err := os.ReadFile(k.Filepath)
30: 		if err != nil {
31: 			return nil, errors.Errorf("error reading secret file for %q: %v", k.Keyname, err)
32: 		}
33: 		secret = keyBytes
34: 	} else {
35: 		// Either the user has set none of EnvVarName or Filepath or both in their config. Either way we return an error.
36: 		return nil, errors.Errorf(
37: 			"must use only one of EnvVarName and Filepath, EnvVarName: %q, Filepath: %q",
38: 			k.EnvVarName, k.Filepath,
39: 		)
40: 	}
41: 
42: 	if len(secret) != 32 {
43: 		return nil, errors.Errorf("invalid key length: %d, expected 32 bytes", len(secret))
44: 	}
45: 
46: 	return &Key{
47: 		keyname: k.Keyname,
48: 		version: k.Version,
49: 		secret:  secret,
50: 	}, nil
51: }
52: 
53: // Key is an encryption.Key implementation that uses AES GCM encryption, using a
54: // secret loaded either from an env var or a file
55: type Key struct {
56: 	keyname string
57: 	secret  []byte
58: 	version string
59: }
60: 
61: func (k *Key) Version(ctx context.Context) (encryption.KeyVersion, error) {
62: 	return encryption.KeyVersion{
63: 		Type:    "mounted",
64: 		Name:    k.keyname,
65: 		Version: k.version,
66: 	}, nil
67: }
68: 
69: func (k *Key) Encrypt(ctx context.Context, plaintext []byte) ([]byte, error) {
70: 	ev, err := envelope.Encrypt(plaintext)
71: 	if err != nil {
72: 		return nil, errors.Wrap(err, "envelope encrypting plaintext")
73: 	}
74: 
75: 	// Encrypt the envelope key using the keys secret.
76: 	keyCiphertext, keyNonce, err := aeshelper.Encrypt(k.secret, ev.Key)
77: 	if err != nil {
78: 		return nil, err
79: 	}
80: 
81: 	// Store both the nonce and the ciphertext in the wrappedKey field.
82: 	wrappedKey := append(keyNonce, keyCiphertext...)
83: 
84: 	ek := wrapper.StorableEncryptedKey{
85: 		Mechanism:  mechanismEnvelope,
86: 		KeyName:    k.keyname,
87: 		WrappedKey: wrappedKey,
88: 		Ciphertext: ev.Ciphertext,
89: 		Nonce:      ev.Nonce,
90: 	}
91: 
92: 	return ek.Serialize()
93: }
94: 
95: func (k *Key) Decrypt(ctx context.Context, ciphertext []byte) (*encryption.Secret, error) {
96: 	wr, err := wrapper.FromCiphertext(ciphertext)
97: 	if err != nil {
98: 		return nil, errors.Wrap(err, "unmarshalling encrypted key")
99: 	}
100: 
101: 	if wr.Mechanism == "" {
102: 		wr.Mechanism = mechanismEncrypt
103: 	}
104: 
105: 	if !strings.HasPrefix(wr.KeyName, k.keyname) {
106: 		return nil, errors.New("invalid key name, are you trying to decrypt something with the wrong key?")
107: 	}
108: 
109: 	switch wr.Mechanism {
110: 	case mechanismEncrypt:
111: 		nonceSize, err := getNonceSize(k.secret)
112: 		if err != nil {
113: 			return nil, err
114: 		}
115: 		if len(wr.Ciphertext) < nonceSize {
116: 			return nil, errors.New("malformed ciphertext")
117: 		}
118: 		plaintext, err := aeshelper.Decrypt(k.secret, wr.Ciphertext[nonceSize:], wr.Ciphertext[:nonceSize])
119: 		if err != nil {
120: 			return nil, err
121: 		}
122: 
123: 		s := encryption.NewSecret(string(plaintext))
124: 		return &s, nil
125: 	case mechanismEnvelope:
126: 		nonceSize, err := getNonceSize(k.secret)
127: 		if err != nil {
128: 			return nil, err
129: 		}
130: 		if len(wr.WrappedKey) < nonceSize {
131: 			return nil, errors.New("malformed ciphertext")
132: 		}
133: 		keyCiphertext := wr.WrappedKey[nonceSize:]
134: 		keyNonce := wr.WrappedKey[:nonceSize]
135: 
136: 		key, err := aeshelper.Decrypt(k.secret, keyCiphertext, keyNonce)
137: 		if err != nil {
138: 			return nil, err
139: 		}
140: 
141: 		plaintext, err := envelope.Decrypt(&envelope.Envelope{
142: 			Key:        key,
143: 			Ciphertext: wr.Ciphertext,
144: 			Nonce:      wr.Nonce,
145: 		})
146: 		if err != nil {
147: 			return nil, err
148: 		}
149: 
150: 		s := encryption.NewSecret(string(plaintext))
151: 		return &s, nil
152: 	default:
153: 		return nil, errors.Errorf("unsupported encryption mechanism: %s", wr.Mechanism)
154: 	}
155: }
156: 
157: func getNonceSize(secret []byte) (int, error) {
158: 	block, err := aes.NewCipher(secret)
159: 	if err != nil {
160: 		return 0, errors.Wrap(err, "creating AES cipher")
161: 	}
162: 	gcm, err := cipher.NewGCM(block)
163: 	if err != nil {
164: 		return 0, errors.Wrap(err, "creating GCM block cipher")
165: 	}
166: 	return gcm.NonceSize(), nil
167: }
