{"content":"1: package awskms
2: 
3: import (
4: 	"context"
5: 	"encoding/base64"
6: 	"encoding/json"
7: 	"strings"
8: 
9: 	"github.com/aws/aws-sdk-go-v2/aws"
10: 	"github.com/aws/aws-sdk-go-v2/config"
11: 	"github.com/aws/aws-sdk-go-v2/service/kms"
12: 
13: 	"github.com/sourcegraph/sourcegraph/internal/encryption"
14: 	"github.com/sourcegraph/sourcegraph/internal/encryption/aeshelper"
15: 	"github.com/sourcegraph/sourcegraph/internal/encryption/envelope"
16: 	"github.com/sourcegraph/sourcegraph/internal/encryption/wrapper"
17: 	"github.com/sourcegraph/sourcegraph/lib/errors"
18: 	"github.com/sourcegraph/sourcegraph/schema"
19: )
20: 
21: const (
22: 	// mechanismEncrypt is the mechanism used prior to the introduction of the envelope helper.
23: 	mechanismEncrypt = "encrypt"
24: 	// mechanismEnvelope is the default for all new encrypted values, which uses the envelope helper.
25: 	mechanismEnvelope = "envelope"
26: )
27: 
28: func NewKey(ctx context.Context, keyConfig schema.AWSKMSEncryptionKey) (encryption.Key, error) {
29: 	defaultConfig, err := config.LoadDefaultConfig(ctx, awsConfigOptsForKeyConfig(keyConfig)...)
30: 	if err != nil {
31: 		return nil, errors.Wrap(err, "loading config for aws KMS")
32: 	}
33: 	return newKey(ctx, keyConfig, defaultConfig)
34: }
35: 
36: func newKey(ctx context.Context, keyConfig schema.AWSKMSEncryptionKey, config aws.Config) (*Key, error) {
37: 	k := &Key{
38: 		keyID:  keyConfig.KeyId,
39: 		client: kms.NewFromConfig(config),
40: 	}
41: 	// Test client connection.
42: 	_, err := k.Version(ctx)
43: 	return k, err
44: }
45: 
46: func awsConfigOptsForKeyConfig(keyConfig schema.AWSKMSEncryptionKey) []func(*config.LoadOptions) error {
47: 	configOpts := []func(*config.LoadOptions) error{}
48: 	if keyConfig.Region != "" {
49: 		configOpts = append(configOpts, config.WithRegion(keyConfig.Region))
50: 	}
51: 	if keyConfig.CredentialsFile != "" {
52: 		configOpts = append(configOpts, config.WithSharedCredentialsFiles([]string{keyConfig.CredentialsFile}))
53: 	}
54: 	return configOpts
55: }
56: 
57: type Key struct {
58: 	keyID  string
59: 	client *kms.Client
60: }
61: 
62: func (k *Key) Version(ctx context.Context) (encryption.KeyVersion, error) {
63: 	key, err := k.client.DescribeKey(ctx, &kms.DescribeKeyInput{
64: 		KeyId: &k.keyID,
65: 	})
66: 	if err != nil {
67: 		return encryption.KeyVersion{}, errors.Wrap(err, "getting key version")
68: 	}
69: 	return encryption.KeyVersion{
70: 		Type:    "awskms",
71: 		Version: *key.KeyMetadata.Arn,
72: 		Name:    *key.KeyMetadata.KeyId,
73: 	}, nil
74: }
75: 
76: // Decrypt a secret, it must have been encrypted with the same Key.
77: // Encrypted secrets are a base64 encoded string containing the original content.
78: func (k *Key) Decrypt(ctx context.Context, cipherText []byte) (*encryption.Secret, error) {
79: 	wr, err := wrapper.FromCiphertext(cipherText)
80: 	if err != nil {
81: 		return nil, err
82: 	}
83: 
84: 	if wr.Mechanism == "" {
85: 		wr.Mechanism = mechanismEncrypt
86: 	}
87: 
88: 	switch wr.Mechanism {
89: 	case mechanismEncrypt:
90: 		buf, err := base64.StdEncoding.DecodeString(string(cipherText))
91: 		if err != nil {
92: 			return nil, err
93: 		}
94: 		ev := encryptedValue{}
95: 		err = json.Unmarshal(buf, &ev)
96: 		if err != nil {
97: 			return nil, err
98: 		}
99: 
100: 		res, err := k.client.Decrypt(ctx, &kms.DecryptInput{
101: 			CiphertextBlob: ev.Key,
102: 			KeyId:          &k.keyID,
103: 		})
104: 		if err != nil {
105: 			return nil, err
106: 		}
107: 
108: 		// Decrypt ciphertext.
109: 		decBuf, err := aeshelper.Decrypt(res.Plaintext, ev.Ciphertext, ev.Nonce)
110: 		if err != nil {
111: 			return nil, err
112: 		}
113: 
114: 		s := encryption.NewSecret(string(decBuf))
115: 		return &s, nil
116: 	case mechanismEnvelope:
117: 		if !strings.HasSuffix(wr.KeyName, k.keyID) {
118: 			return nil, errors.New("invalid key name, are you trying to decrypt something with the wrong key?")
119: 		}
120: 
121: 		// First, use KMS to decrypt the envelope key.
122: 		res, err := k.client.Decrypt(ctx, &kms.DecryptInput{
123: 			CiphertextBlob: wr.WrappedKey,
124: 			KeyId:          &k.keyID,
125: 		})
126: 		if err != nil {
127: 			return nil, err
128: 		}
129: 
130: 		// Next, decrypt the envelope.
131: 		plaintext, err := envelope.Decrypt(&envelope.Envelope{
132: 			Key:        res.Plaintext,
133: 			Nonce:      wr.Nonce,
134: 			Ciphertext: wr.Ciphertext,
135: 		})
136: 		if err != nil {
137: 			return nil, err
138: 		}
139: 
140: 		s := encryption.NewSecret(string(plaintext))
141: 		return &s, nil
142: 	default:
143: 		return nil, errors.Newf("invalid mechanism %q", wr.Mechanism)
144: 	}
145: }
146: 
147: // Encrypt a secret, storing it as a base64 encoded string.
148: func (k *Key) Encrypt(ctx context.Context, plaintext []byte) ([]byte, error) {
149: 	ev, err := envelope.Encrypt(plaintext)
150: 	if err != nil {
151: 		return nil, errors.Wrap(err, "envelope encrypting payload")
152: 	}
153: 
154: 	// Encrypt the key of the envelope.
155: 	res, err := k.client.Encrypt(ctx, &kms.EncryptInput{
156: 		KeyId:     &k.keyID,
157: 		Plaintext: ev.Key,
158: 	})
159: 	if err != nil {
160: 		return nil, errors.Wrap(err, "encrypting envelope key")
161: 	}
162: 
163: 	ek := wrapper.StorableEncryptedKey{
164: 		Mechanism:  mechanismEnvelope,
165: 		KeyName:    *res.KeyId,
166: 		WrappedKey: res.CiphertextBlob,
167: 		Ciphertext: ev.Ciphertext,
168: 		Nonce:      ev.Nonce,
169: 	}
170: 
171: 	return ek.Serialize()
172: }
173: 
174: type encryptedValue struct {
175: 	Key        []byte
176: 	Nonce      []byte
177: 	Ciphertext []byte
178: }
