{"content":"1: package encryption
2: 
3: import (
4: 	"context"
5: 	"encoding/json"
6: )
7: 
8: // JSONEncryptable wraps a value of type T and an encryption key and handles lazily encoding/encrypting
9: // and decrypting/decoding that value. This struct should be used in all places where a JSON-serialized
10: // value is encrypted at-rest to maintain a consistent handling of data with security concerns.
11: //
12: // This struct should always be passed by reference.
13: type JSONEncryptable[T any] struct {
14: 	*Encryptable
15: }
16: 
17: // NewUnencryptedJSON creates a new JSON encryptable from the given value.
18: func NewUnencryptedJSON[T any](value T) (*JSONEncryptable[T], error) {
19: 	serialized, err := json.Marshal(value)
20: 	if err != nil {
21: 		return nil, err
22: 	}
23: 
24: 	return &JSONEncryptable[T]{Encryptable: NewUnencrypted(string(serialized))}, nil
25: }
26: 
27: // NewEncryptedJSON creates a new JSON encryptable an encrypted value and a relevant encryption key.
28: func NewEncryptedJSON[T any](cipher, keyID string, key Key) *JSONEncryptable[T] {
29: 	return &JSONEncryptable[T]{Encryptable: NewEncrypted(cipher, keyID, key)}
30: }
31: 
32: // Decrypt decrypts and returns the underlying value as a T. This method may make an external API call
33: // to decrypt the underlying encrypted value, but will memoize the result so that subsequent calls will
34: // be cheap.
35: func (e *JSONEncryptable[T]) Decrypt(ctx context.Context) (value T, _ error) {
36: 	serialized, err := e.Encryptable.Decrypt(ctx)
37: 	if err != nil {
38: 		return value, err
39: 	}
40: 
41: 	if err := json.Unmarshal([]byte(serialized), &value); err != nil {
42: 		return value, err
43: 	}
44: 
45: 	return value, nil
46: }
47: 
48: // Set updates the underlying value.
49: func (e *JSONEncryptable[T]) Set(value T) error {
50: 	serialized, err := json.Marshal(value)
51: 	if err != nil {
52: 		return err
53: 	}
54: 
55: 	e.mutex.Lock()
56: 	defer e.mutex.Unlock()
57: 
58: 	e.decrypted = &decryptedValue{string(serialized), nil}
59: 	e.encrypted = nil
60: 	return nil
61: }
62: 
63: // DecryptJSON decrypts the encryptable value. This method may make an external
64: // API call to decrypt the underlying encrypted value, but will memoize the result so that subsequent calls
65: // will be cheap.
66: func DecryptJSON[T any](ctx context.Context, e *JSONEncryptable[any]) (*T, error) {
67: 	var value T
68: 
69: 	serialized, err := e.Encryptable.Decrypt(ctx)
70: 	if err != nil {
71: 		return nil, err
72: 	}
73: 
74: 	if err := json.Unmarshal([]byte(serialized), &value); err != nil {
75: 		return nil, err
76: 	}
77: 
78: 	return &value, nil
79: }
