{"content":"1: package aeshelper
2: 
3: import (
4: 	"crypto/aes"
5: 	"crypto/cipher"
6: 	"crypto/rand"
7: 	"io"
8: 
9: 	"github.com/sourcegraph/sourcegraph/lib/errors"
10: )
11: 
12: // Encrypt encrypts the plaintext using the given secret.
13: // secret should be exactly 32 bytes to encrypt using AES-256.
14: func Encrypt(secret, plaintext []byte) (ciphertext, nonce []byte, _ error) {
15: 	if len(secret) != 32 {
16: 		return nil, nil, errors.New("secret is not 32 characters long")
17: 	}
18: 
19: 	block, err := aes.NewCipher(secret)
20: 	if err != nil {
21: 		return nil, nil, errors.Wrap(err, "generate new AES cipher")
22: 	}
23: 
24: 	aesGCM, err := cipher.NewGCM(block)
25: 	if err != nil {
26: 		return nil, nil, errors.Wrap(err, "generate new GCM cipher")
27: 	}
28: 
29: 	nonce = make([]byte, aesGCM.NonceSize())
30: 	if _, err = io.ReadFull(rand.Reader, nonce); err != nil {
31: 		return nil, nil, errors.Wrap(err, "generate nonce")
32: 	}
33: 
34: 	ciphertext = aesGCM.Seal(nil, nonce, plaintext, nil)
35: 
36: 	return ciphertext, nonce, nil
37: }
38: 
39: // Decrypt decrypts the data from the given aes encrypted value.
40: // secret should be exactly 32 bytes.
41: func Decrypt(secret, ciphertext, nonce []byte) ([]byte, error) {
42: 	block, err := aes.NewCipher(secret)
43: 	if err != nil {
44: 		return nil, errors.Wrap(err, "generate new AES cipher")
45: 	}
46: 
47: 	aesGCM, err := cipher.NewGCM(block)
48: 	if err != nil {
49: 		return nil, errors.Wrap(err, "generate new GCM cipher")
50: 	}
51: 
52: 	return aesGCM.Open(nil, nonce, ciphertext, nil)
53: }
