{"content":"1: package wrapper
2: 
3: import (
4: 	"encoding/base64"
5: 	"encoding/json"
6: 
7: 	"github.com/sourcegraph/sourcegraph/lib/errors"
8: )
9: 
10: type StorableEncryptedKey struct {
11: 	// Mechanism is used to store the way the value was encrypted, like envelope AES encryption.
12: 	Mechanism string
13: 	// KeyName is the name of the key used to encrypt the value.
14: 	KeyName string
15: 	// WrappedKey optionally contains an encrypted key that was used to encrypt the ciphertext.
16: 	WrappedKey []byte
17: 	// Ciphertext contains the encrypted value.
18: 	Ciphertext []byte
19: 	// Nonce is an additional value to store a nonce that was used to encrypt Ciphertext.
20: 	Nonce []byte
21: }
22: 
23: func FromCiphertext(ciphertext []byte) (*StorableEncryptedKey, error) {
24: 	data, err := base64.StdEncoding.DecodeString(string(ciphertext))
25: 	if err != nil {
26: 		return nil, errors.Wrap(err, "failed to decode ciphertext")
27: 	}
28: 	var sek StorableEncryptedKey
29: 	if err := json.Unmarshal(data, &sek); err != nil {
30: 		return nil, errors.Wrap(err, "failed to unmarshal ciphertext into StorableEncryptedKey")
31: 	}
32: 
33: 	return &sek, nil
34: }
35: 
36: func (sek *StorableEncryptedKey) Serialize() ([]byte, error) {
37: 	jsonKey, err := json.Marshal(sek)
38: 	if err != nil {
39: 		return nil, errors.Wrap(err, "marshaling StorableEncryptedKey to JSON")
40: 	}
41: 	return []byte(base64.StdEncoding.EncodeToString(jsonKey)), nil
42: }
43: ","url":"https://sourcegraph.sourcegraph.com/github.com/sourcegraph/sourcegraph@2182d53b963752f43e9f39205715f71160798bb2/-/blob/internal/encryption/wrapper/encryptedvalue.go"}

